procedure swap_list(m: list_type);
var
p,q: pos_type;
a,b: list_info_type;
begin
     p:=list_anchor(m);
     p:=list_next(m,p);
     q:=list_anchor(m);
     while (q<>nil) do
           q:=list_next(m,q);
     q:=list_prev(m,q); {now q is the last cell}

     while ( (p<>q) and (list_next(m,q)<>p) and (list_prev(m,p)<>q))  do
           begin
                list_retrieve ( m,p,a);
                list_retrieve ( m,q,b);
                list_update (m,p,b);
                list_update (m,q,a);
                p:=list_next(m,p);
                q:=list_prev (m,q);
           end;
end;


begin
     list_init (l);
     bulid_list(l);
      writeln('the list before the swap:');
     print_list(l);
     swap_list(l);
     writeln('the list after the swap:');
     print_list(l);
     readkey;
end.

