{----------complexity: O(n)------------------------}
function Array_Sorted (a: ar; n: integer): boolean;
begin
     if n=1 then
        Array_Sorted := true
     else
         if a[n]>=a[n-1] then
            Array_Sorted:= Array_Sorted(a, n-1)
         else
             Array_Sorted:=false;
end;

